insert into public.interaction_types (key,name,payload_schema,notes) values ('listen','Listen & choose','{"hint":"{ \"say\": \"buh\", \"choices\": [\"b\",\"d\",\"p\"], \"answer\": 0 }"}'::jsonb,'Hear a sound, pick the match.')
